// TargetTrainer.tsx — Screen HZ
// Generated by Gemini for screenhz.com

import { useState, useRef, useEffect, useCallback } from 'react'

// --- TYPES ---

type GameMode = 'flicker' | 'flicking' | 'tracking' | 'precision';

interface CrosshairSettings {
  enabled: boolean;
  color: string;
  length: number;
  thickness: number;
  gap: number;
  dot: boolean;
}

interface Settings {
  targetSize: 'small' | 'medium' | 'large';
  duration: 15 | 30 | 60 | 0; // 0 for Infinity
  speed: number;
  crosshair: CrosshairSettings;
}

interface Target {
  id: number;
  x: number;
  y: number;
  radius: number;
  spawnTime: number;
  vx?: number;
  vy?: number;
  phaseX?: number;
  phaseY?: number;
}

interface ClickPoint {
  x: number;
  y: number;
  isHit: boolean;
}

interface RoundResult {
  score: number;
  accuracy: number;
  avgReaction: number;
  hits: number;
  shots: number;
  bullseyes: number;
  bestStreak: number;
  trackPercent: number;
  reactionTimes: number[];
  clicks: ClickPoint[];
  duration: number;
  mode: GameMode;
  date: string;
}

interface RecordData {
  score: number;
  accuracy: number;
  avgReaction: number;
  bullseyeRatio?: number;
  trackPercent?: number;
  date: string;
}

interface Records {
  flicker?: RecordData;
  flicking?: RecordData;
  tracking?: RecordData;
  precision?: RecordData;
}

interface DeltaStats {
  score: number;
  accuracy: number;
  avgReaction: number;
}

// --- CONSTANTS ---

const TARGET_SIZES = {
  small: 12,
  medium: 20,
  large: 30,
};

const BUCKETS = [
  { label: '<100ms', max: 100, color: 'var(--color-neon)' },
  { label: '100-150', max: 150, color: 'var(--color-neon)' },
  { label: '150-200', max: 200, color: 'var(--color-cyber)' },
  { label: '200-250', max: 250, color: 'var(--color-cyber)' },
  { label: '250-300', max: 300, color: '#f59e0b' },
  { label: '300-400', max: 400, color: '#f59e0b' },
  { label: '400ms+', max: Infinity, color: 'var(--color-muted)' },
];

const STORAGE_KEYS = {
  SETTINGS: 'screenhz_trainer_settings',
  RECORDS: 'screenhz_records',
};

const DEFAULT_SETTINGS: Settings = {
  targetSize: 'medium',
  duration: 30,
  speed: 1.0,
  crosshair: {
    enabled: false,
    color: '#00ff00',
    length: 6,
    thickness: 2,
    gap: 2,
    dot: false,
  },
};

// --- COMPONENT ---

export default function TargetTrainer() {
  // Game State
  const [gameState, setGameState] = useState<'idle' | 'playing' | 'finished'>('idle');
  const [isPaused, setIsPaused] = useState(false);
  const [mode, setMode] = useState<GameMode>('flicker');
  const [settings, setSettings] = useState<Settings>(DEFAULT_SETTINGS);
  const [showSettings, setShowSettings] = useState(false);
  
  // HUD State (Synced from refs via RAF)
  const [score, setScore] = useState(0);
  const [timeLeft, setTimeLeft] = useState(30);
  const [fps, setFps] = useState(0);
  const [streak, setStreak] = useState(0);
  const [accuracy, setAccuracy] = useState(0);
  
  // Results & Records
  const [result, setResult] = useState<RoundResult | null>(null);
  const [records, setRecords] = useState<Records>({});
  const [prevResult, setPrevResult] = useState<RoundResult | null>(null);
  const [isNewRecord, setIsNewRecord] = useState(false);

  // Refs for high-performance game loop
  const containerRef = useRef<HTMLDivElement>(null);
  const containerRectRef = useRef<DOMRect | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const heatmapCanvasRef = useRef<HTMLCanvasElement>(null);
  const distributionCanvasRef = useRef<HTMLCanvasElement>(null);
  const crosshairRef = useRef<HTMLDivElement>(null);

  // HUD DOM Refs for performance
  const scoreHudRef = useRef<HTMLSpanElement>(null);
  const fpsHudRef = useRef<HTMLSpanElement>(null);
  const streakHudRef = useRef<HTMLSpanElement>(null);
  const accuracyHudRef = useRef<HTMLSpanElement>(null);
  const timeHudRef = useRef<HTMLSpanElement>(null);
  
  const targetsRef = useRef<Target[]>([]);
  const gameStateRef = useRef(gameState);
  const isPausedRef = useRef(false);
  const scoreRef = useRef(0);
  const streakRef = useRef(0);
  const bestStreakRef = useRef(0);
  const hitsRef = useRef(0);
  const shotsRef = useRef(0);
  const bullseyesRef = useRef(0);
  const reactionTimesRef = useRef<number[]>([]);
  const clicksRef = useRef<ClickPoint[]>([]);
  const trackTicksRef = useRef(0);
  const totalTicksRef = useRef(0);
  
  const lastTimeRef = useRef(0);
  const startTimeRef = useRef(0);
  const pauseTimeRef = useRef(0);
  const totalPausedDurationRef = useRef(0);
  const frameCountRef = useRef(0);
  const lastFpsUpdateRef = useRef(0);
  const rafRef = useRef<number>(0);
  const nextTargetIdRef = useRef(0);
  const lastSpawnTimeRef = useRef(0);
  const lastTrackCheckRef = useRef(0);

  // Sync ref with state
  useEffect(() => {
    gameStateRef.current = gameState;
  }, [gameState]);

  useEffect(() => {
    isPausedRef.current = isPaused;
  }, [isPaused]);

  // Sync container rect on resize/scroll
  useEffect(() => {
    const updateRect = () => {
      if (containerRef.current) {
        containerRectRef.current = containerRef.current.getBoundingClientRect();
      }
    };
    
    updateRect();
    window.addEventListener('resize', updateRect);
    window.addEventListener('scroll', updateRect);
    return () => {
      window.removeEventListener('resize', updateRect);
      window.removeEventListener('scroll', updateRect);
    };
  }, []);

  // Handle Pause on Mouse Leave
  const handleMouseEnter = () => {
    if (containerRef.current) {
      containerRectRef.current = containerRef.current.getBoundingClientRect();
    }
    
    if (gameState === 'playing' && isPaused) {
      const now = performance.now();
      const pausedDuration = now - pauseTimeRef.current;
      totalPausedDurationRef.current += pausedDuration;
      
      // Adjust all active target spawn times so they don't expire while paused
      targetsRef.current = targetsRef.current.map(t => ({
        ...t,
        spawnTime: t.spawnTime + pausedDuration
      }));
      
      // Adjust last spawn time too
      lastSpawnTimeRef.current += pausedDuration;
      lastTrackCheckRef.current += pausedDuration;

      setIsPaused(false);
    }
  };

  const handleMouseLeave = () => {
    if (gameState === 'playing' && !isPaused) {
      pauseTimeRef.current = performance.now();
      setIsPaused(true);
    }
  };

  // Load Settings & Records
  useEffect(() => {
    const savedSettings = localStorage.getItem(STORAGE_KEYS.SETTINGS);
    if (savedSettings) setSettings(JSON.parse(savedSettings));
    
    const savedRecords = localStorage.getItem(STORAGE_KEYS.RECORDS);
    if (savedRecords) setRecords(JSON.parse(savedRecords));
  }, []);

  // Save Settings
  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.SETTINGS, JSON.stringify(settings));
  }, [settings]);

  // --- GAME LOGIC ---

  const spawnTarget = useCallback(() => {
    if (!containerRef.current || !containerRectRef.current) return;
    const rect = containerRectRef.current;
    const radius = TARGET_SIZES[settings.targetSize];
    
    let x, y;
    if (mode === 'flicking' && targetsRef.current.length > 0) {
      const last = targetsRef.current[targetsRef.current.length - 1];
      const minDistance = rect.width * 0.4;
      let attempts = 0;
      do {
        x = radius + Math.random() * (rect.width - radius * 2);
        y = radius + Math.random() * (rect.height - radius * 2);
        const dist = Math.sqrt(Math.pow(x - last.x, 2) + Math.pow(y - last.y, 2));
        if (dist >= minDistance) break;
        attempts++;
      } while (attempts < 50);
    } else {
      x = radius + Math.random() * (rect.width - radius * 2);
      y = radius + Math.random() * (rect.height - radius * 2);
    }

    const newTarget: Target = {
      id: nextTargetIdRef.current++,
      x,
      y,
      radius,
      spawnTime: performance.now(),
    };

    if (mode === 'tracking') {
      newTarget.phaseX = Math.random() * Math.PI * 2;
      newTarget.phaseY = Math.random() * Math.PI * 2;
    }

    targetsRef.current = [...targetsRef.current, newTarget];
    lastSpawnTimeRef.current = performance.now();
  }, [mode, settings.targetSize]);

  const startGame = () => {
    // Reset Refs
    scoreRef.current = 0;
    streakRef.current = 0;
    bestStreakRef.current = 0;
    hitsRef.current = 0;
    shotsRef.current = 0;
    bullseyesRef.current = 0;
    reactionTimesRef.current = [];
    clicksRef.current = [];
    trackTicksRef.current = 0;
    totalTicksRef.current = 0;
    targetsRef.current = [];
    nextTargetIdRef.current = 0;
    lastTimeRef.current = performance.now();
    startTimeRef.current = performance.now();
    totalPausedDurationRef.current = 0;
    lastSpawnTimeRef.current = 0;
    lastTrackCheckRef.current = 0;
    
    setScore(0);
    setStreak(0);
    setAccuracy(0);
    setResult(null);
    setIsNewRecord(false);
    setIsPaused(false);
    setGameState('playing');
    
    // Initial Spawn
    spawnTarget();
    
    rafRef.current = requestAnimationFrame(gameLoop);
  };

  const endGame = () => {
    cancelAnimationFrame(rafRef.current);
    setGameState('finished');
    setIsPaused(false);
    
    const duration = settings.duration || 30;
    const acc = shotsRef.current > 0 ? (hitsRef.current / shotsRef.current) * 100 : 0;
    const avgReact = reactionTimesRef.current.length > 0
      ? reactionTimesRef.current.reduce((a, b) => a + b, 0) / reactionTimesRef.current.length
      : 0;
    const trackPct = totalTicksRef.current > 0 ? (trackTicksRef.current / totalTicksRef.current) * 100 : 0;

    const roundResult: RoundResult = {
      score: scoreRef.current,
      accuracy: acc,
      avgReaction: avgReact,
      hits: hitsRef.current,
      shots: shotsRef.current,
      bullseyes: bullseyesRef.current,
      bestStreak: bestStreakRef.current,
      trackPercent: trackPct,
      reactionTimes: [...reactionTimesRef.current],
      clicks: [...clicksRef.current],
      duration,
      mode,
      date: new Date().toISOString(),
    };

    setResult(roundResult);
    checkAndSaveRecord(roundResult);
    setPrevResult(roundResult);
  };

  const checkAndSaveRecord = (res: RoundResult) => {
    const currentModeRecord = records[res.mode];
    let isBetter = false;

    if (!currentModeRecord) {
      isBetter = true;
    } else {
      if (res.mode === 'tracking') {
        if (res.trackPercent > (currentModeRecord.trackPercent || 0)) isBetter = true;
      } else {
        if (res.score > currentModeRecord.score) isBetter = true;
      }
    }

    if (isBetter) {
      setIsNewRecord(true);
      const newRecords = {
        ...records,
        [res.mode]: {
          score: res.score,
          accuracy: res.accuracy,
          avgReaction: res.avgReaction,
          bullseyeRatio: res.mode === 'precision' ? (res.bullseyes / (res.hits || 1)) : undefined,
          trackPercent: res.mode === 'tracking' ? res.trackPercent : undefined,
          date: res.date,
        },
      };
      setRecords(newRecords);
      localStorage.setItem(STORAGE_KEYS.RECORDS, JSON.stringify(newRecords));
    }
  };

  const gameLoop = (time: number) => {
    if (gameStateRef.current !== 'playing') return;
    
    if (isPausedRef.current) {
      lastTimeRef.current = time;
      rafRef.current = requestAnimationFrame(gameLoop);
      return;
    }

    const dt = time - lastTimeRef.current;
    lastTimeRef.current = time;

    // FPS Counter
    frameCountRef.current++;
    if (time - lastFpsUpdateRef.current > 500) {
      const calculatedFps = Math.round((frameCountRef.current * 1000) / (time - lastFpsUpdateRef.current));
      fpsRef.current = calculatedFps;
      frameCountRef.current = 0;
      lastFpsUpdateRef.current = time;
    }

    // Timer (Adjusted for paused duration)
    const elapsed = (time - startTimeRef.current - totalPausedDurationRef.current) / 1000;
    if (settings.duration > 0) {
      const remaining = Math.max(0, settings.duration - elapsed);
      if (remaining <= 0) {
        endGame();
        return;
      }
    }

    // Mode Specific Logic
    const rect = containerRectRef.current;
    if (!rect) return;

    if (mode === 'tracking') {
      const target = targetsRef.current[0];
      if (target) {
        const speedMultiplier = settings.speed;
        const adjustedTime = (time - totalPausedDurationRef.current);
        const timeScale = adjustedTime * 0.002 * speedMultiplier;
        
        // Sine wave movement
        target.x = rect.width / 2 + (rect.width * 0.4) * Math.sin(timeScale + (target.phaseX || 0));
        target.y = rect.height / 2 + (rect.height * 0.4) * Math.cos(timeScale * 0.7 + (target.phaseY || 0));
        
        // Tracking Score & Ticks
        if (time - lastTrackCheckRef.current >= 100) {
          totalTicksRef.current++;
          lastTrackCheckRef.current = time;
          
          const dist = Math.sqrt(Math.pow(mousePosRef.current.x - target.x, 2) + Math.pow(mousePosRef.current.y - target.y, 2));
          if (dist <= target.radius) {
            trackTicksRef.current++;
            scoreRef.current += 10;
          }
        }
      }
    } else {
      // Despawn old targets
      const lifetime = mode === 'flicking' ? 1500 : 1800;
      const initialLength = targetsRef.current.length;
      targetsRef.current = targetsRef.current.filter(t => (time - (t.spawnTime + (t.pausedAt ? (time - t.pausedAt) : 0))) < lifetime);
      // Actually targetsRef doesn't have pausedAt. I'll just adjust spawnTime on resume or handle it differently.
      // Better way: adjust all spawn times in targetsRef when resuming.
    }

    // Spawning logic (relative to total duration)
    if (mode !== 'tracking') {
      if (mode === 'flicker') {
        if (targetsRef.current.length < 3 && (time - lastSpawnTimeRef.current) > 900) {
          spawnTarget();
        }
      } else if (mode === 'flicking' || mode === 'precision') {
        if (targetsRef.current.length === 0) {
          spawnTarget();
        }
      }
    }

    // HUD state updates throttled or direct DOM
    if (scoreHudRef.current) scoreHudRef.current.innerText = mode === 'tracking' ? Math.round(scoreRef.current).toString() : scoreRef.current.toString();
    if (fpsHudRef.current) fpsHudRef.current.innerText = fpsRef.current.toString();
    if (streakHudRef.current) streakHudRef.current.innerText = streakRef.current > 0 ? `🔥 ${streakRef.current}` : '0';
    if (accuracyHudRef.current) accuracyHudRef.current.innerText = `${Math.round(shotsRef.current > 0 ? (hitsRef.current / shotsRef.current) * 100 : 0)}%`;
    if (timeHudRef.current) {
      const displayTime = settings.duration > 0 ? Math.ceil(Math.max(0, settings.duration - elapsed)) : 999;
      timeHudRef.current.innerText = displayTime === 999 ? '∞' : displayTime.toString();
      if (settings.duration > 0 && displayTime <= 5) {
        timeHudRef.current.classList.add('text-red-500', 'animate-pulse');
      } else {
        timeHudRef.current.classList.remove('text-red-500', 'animate-pulse');
      }
    }

    rafRef.current = requestAnimationFrame(gameLoop);
  };

  const fpsRef = useRef(0);
  useEffect(() => {
    // Only update React state for non-critical HUD every 500ms
    const interval = setInterval(() => {
      if (gameStateRef.current === 'playing') {
        setFps(fpsRef.current);
      }
    }, 500);
    return () => clearInterval(interval);
  }, []);

  const [showBullseyeFlash, setShowBullseyeFlash] = useState(false);
  const bullseyeTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  const handleCanvasClick = (e: React.MouseEvent) => {
    if (gameState !== 'playing') return;
    if (mode === 'tracking') return; // No clicks in tracking

    const rect = containerRectRef.current;
    if (!rect) return;

    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;

    let hit = false;
    let hitTargetId = -1;
    let isBullseye = false;

    for (const target of targetsRef.current) {
      const dist = Math.sqrt(Math.pow(mouseX - target.x, 2) + Math.pow(mouseY - target.y, 2));
      if (dist <= target.radius) {
        hit = true;
        hitTargetId = target.id;
        
        if (mode === 'precision') {
          if (dist <= 8) { // 16px diameter / 2
            isBullseye = true;
          }
        }
        break;
      }
    }

    shotsRef.current++;
    clicksRef.current.push({ x: mouseX, y: mouseY, isHit: hit });

    if (hit) {
      hitsRef.current++;
      streakRef.current++;
      if (streakRef.current > bestStreakRef.current) bestStreakRef.current = streakRef.current;
      
      const hitTime = performance.now();
      const target = targetsRef.current.find(t => t.id === hitTargetId);
      if (target) {
        reactionTimesRef.current.push(hitTime - target.spawnTime);
      }

      if (mode === 'precision') {
        if (isBullseye) {
          scoreRef.current += 300;
          bullseyesRef.current++;

          setShowBullseyeFlash(true);
          if (bullseyeTimeoutRef.current) clearTimeout(bullseyeTimeoutRef.current);
          bullseyeTimeoutRef.current = setTimeout(() => setShowBullseyeFlash(false), 600);
        } else {
          scoreRef.current += 100;
        }
      } else {
        scoreRef.current += 100;
      }

      // Remove target and spawn next if needed
      targetsRef.current = targetsRef.current.filter(t => t.id !== hitTargetId);
      if (mode === 'flicking' || mode === 'precision') {
        spawnTarget();
      }
    } else {
      streakRef.current = 0;
    }
  };

  // Mouse move for tracking
  const mousePosRef = useRef({ x: 0, y: 0 });
  const handleMouseMove = (e: React.MouseEvent) => {
    const rect = containerRectRef.current;
    if (!rect) return;
    
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    mousePosRef.current = { x, y };

    if (crosshairRef.current) {
      // The crosshair container is w-0 h-0 and flex centered, 
      // so simply translating to (x, y) keeps it perfectly centered.
      crosshairRef.current.style.transform = `translate3d(${x}px, ${y}px, 0)`;
      crosshairRef.current.style.display = settings.crosshair.enabled ? 'flex' : 'none';
    }

    if (gameStateRef.current !== 'playing') return;
    
    if (mode === 'tracking') {
      const target = targetsRef.current[0];
      if (target) {
        const dist = Math.sqrt(Math.pow(x - target.x, 2) + Math.pow(y - target.y, 2));
        if (dist <= target.radius) {
          const now = performance.now();
          if (now - lastTrackCheckRef.current >= 100) {
            trackTicksRef.current++;
            scoreRef.current += 10;
            lastTrackCheckRef.current = now;
          }
        }
      }
    }
  };

  // --- DRAWING ---

  useEffect(() => {
    if (result && distributionCanvasRef.current) {
      drawDistribution(distributionCanvasRef.current, result.reactionTimes);
    }
    if (result && heatmapCanvasRef.current) {
      drawHeatmap(heatmapCanvasRef.current, result.clicks);
    }
  }, [result]);

  const drawDistribution = (canvas: HTMLCanvasElement, times: number[]) => {
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const { width, height } = canvas;
    ctx.clearRect(0, 0, width, height);

    const counts = BUCKETS.map(b => times.filter(t => t <= b.max && (BUCKETS[BUCKETS.indexOf(b)-1]?.max || 0) < t).length);
    const maxCount = Math.max(...counts, 1);
    const barWidth = width / BUCKETS.length;

    counts.forEach((count, i) => {
      const barHeight = (count / maxCount) * (height - 20);
      ctx.fillStyle = BUCKETS[i].color;
      ctx.fillRect(i * barWidth + 2, height - barHeight - 12, barWidth - 4, barHeight);
      
      // Label
      ctx.fillStyle = 'var(--color-muted)';
      ctx.font = '8px var(--font-mono)';
      ctx.textAlign = 'center';
      ctx.fillText(BUCKETS[i].label.replace('ms', ''), i * barWidth + barWidth / 2, height - 2);
      
      if (count === maxCount && count > 0) {
        ctx.fillStyle = 'var(--color-text)';
        ctx.fillText('▲ most', i * barWidth + barWidth / 2, height - barHeight - 16);
      }
    });
  };

  const drawHeatmap = (canvas: HTMLCanvasElement, clicks: ClickPoint[]) => {
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const { width, height } = canvas;
    ctx.clearRect(0, 0, width, height);
    
    if (clicks.length < 5) {
      ctx.fillStyle = 'var(--color-muted)';
      ctx.font = '10px var(--font-mono)';
      ctx.textAlign = 'center';
      ctx.fillText('Not enough data.', width / 2, height / 2);
      return;
    }

    ctx.globalCompositeOperation = 'lighter';
    const rect = containerRef.current?.getBoundingClientRect();
    const scaleX = width / (rect?.width || 1);
    const scaleY = height / (rect?.height || 1);

    clicks.forEach(c => {
      const x = c.x * scaleX;
      const y = c.y * scaleY;
      const grad = ctx.createRadialGradient(x, y, 0, x, y, 15);
      const color = c.isHit ? 'rgba(255, 107, 53, 0.6)' : 'rgba(255, 255, 255, 0.2)';
      grad.addColorStop(0, color);
      grad.addColorStop(1, 'transparent');
      ctx.fillStyle = grad;
      ctx.beginPath();
      ctx.arc(x, y, 15, 0, Math.PI * 2);
      ctx.fill();
    });
  };

  // --- UI HELPERS ---

  const getInsight = () => {
    if (!result) return "";
    const { mode, avgReaction, accuracy, trackPercent, bullseyes, hits } = result;
    
    if (mode === 'flicker') {
      if (avgReaction < 180) return "Elite reflexes. Your screen latency is within 1 frame at 144Hz.";
      if (avgReaction < 220) return "Sharp reactions. Consistent enough for competitive play.";
      if (avgReaction < 280) return "Average response. Practice daily to shave off 20–40ms.";
      return "Room to improve. Focus on target prediction, not just reaction.";
    }
    if (mode === 'flicking') {
      if (accuracy > 85) return "Precise flicks. Your muscle memory is calibrated well.";
      if (accuracy > 70) return "Good flicking accuracy. Try larger target size to build confidence.";
      return "Flicking is hard — keep going. Consistency comes with repetition.";
    }
    if (mode === 'tracking') {
      if (trackPercent > 75) return "Excellent tracking. Your aim stays glued under pressure.";
      if (trackPercent > 50) return "Solid tracking. Smooth mouse movement beats speed here.";
      return "Tracking needs work. Lower your sensitivity and follow the target.";
    }
    if (mode === 'precision') {
      const ratio = (bullseyes / (hits || 1)) * 100;
      if (ratio > 40) return "Surgical precision. You're headshot material.";
      if (ratio > 20) return "Good center-hitting. Precision improves with lower DPI settings.";
      return "Focus on the inner ring. Slow down and aim before clicking.";
    }
    return "";
  };

  const formatDelta = (prev: number, curr: number, unit = "", invert = false) => {
    const diff = curr - prev;
    if (Math.abs(diff) < 0.1) return <span className="text-muted">±0</span>;
    const isPositive = diff > 0;
    const good = invert ? !isPositive : isPositive;
    return (
      <span style={{ color: good ? 'var(--color-neon)' : 'var(--color-heat)' }}>
        {isPositive ? '+' : ''}{Math.round(diff)}{unit} {isPositive ? '▲' : '▼'}
      </span>
    );
  };

  // Cleanup
  useEffect(() => {
    return () => cancelAnimationFrame(rafRef.current);
  }, []);

  return (
    <div className="flex flex-col gap-4 w-full max-w-5xl mx-auto font-sans text-[var(--color-text)]">
      {/* Header Info */}
      <div className="flex flex-col gap-1 mb-2">
        <span className="text-[var(--color-heat)] font-mono text-[10px] tracking-[0.2em] font-bold">02 — AIM TRAINING</span>
        <h2 className="text-3xl font-display font-bold tracking-tight">Target Trainer</h2>
        <p className="text-[var(--color-muted)] text-sm">Train your aim. See your real FPS.</p>
      </div>

      {/* Mode Selector */}
      <div className="flex flex-wrap gap-2 mb-2">
        {(['flicker', 'flicking', 'tracking', 'precision'] as GameMode[]).map(m => (
          <button
            key={m}
            onClick={() => { setMode(m); setGameState('idle'); }}
            aria-pressed={mode === m}
            className={`px-4 py-1.5 rounded-full text-xs font-mono font-bold uppercase tracking-wider transition-all border ${
              mode === m 
                ? 'bg-[var(--color-heat)] text-white border-[var(--color-heat)]' 
                : 'bg-transparent text-[var(--color-muted)] border-[var(--color-border)] hover:border-[var(--color-muted)]'
            }`}
          >
            {m}
          </button>
        ))}
      </div>

      {/* Settings Toggle */}
      <div className="flex flex-col gap-2">
        <button 
          onClick={() => setShowSettings(!showSettings)}
          className="flex items-center gap-2 text-[var(--color-muted)] hover:text-[var(--color-text)] transition-colors text-xs font-mono"
        >
          <span className="text-lg">⚙</span> SETTINGS
        </button>
        
        {showSettings && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 p-4 bg-[var(--color-surface)] border border-[var(--color-border)] rounded-xl animate-in fade-in slide-in-from-top-2">
            <div className="flex flex-col gap-2">
              <span className="text-[10px] font-mono text-[var(--color-muted)] uppercase">Target Size</span>
              <div className="flex gap-1">
                {(['small', 'medium', 'large'] as const).map(s => (
                  <button
                    key={s}
                    onClick={() => setSettings({ ...settings, targetSize: s })}
                    className={`flex-1 py-1 rounded border text-[10px] font-bold uppercase ${
                      settings.targetSize === s ? 'bg-[var(--color-heat)] text-white border-[var(--color-heat)]' : 'border-[var(--color-border)] text-[var(--color-muted)]'
                    }`}
                  >
                    {s}
                  </button>
                ))}
              </div>
            </div>
            
            <div className="flex flex-col gap-2">
              <span className="text-[10px] font-mono text-[var(--color-muted)] uppercase">Round Duration</span>
              <div className="flex gap-1">
                {([15, 30, 60, 0] as const).map(d => (
                  <button
                    key={d}
                    onClick={() => setSettings({ ...settings, duration: d })}
                    className={`flex-1 py-1 rounded border text-[10px] font-bold uppercase ${
                      settings.duration === d ? 'bg-[var(--color-heat)] text-white border-[var(--color-heat)]' : 'border-[var(--color-border)] text-[var(--color-muted)]'
                    }`}
                  >
                    {d === 0 ? '∞' : `${d}s`}
                  </button>
                ))}
              </div>
            </div>

            {mode === 'tracking' && (
              <div className="flex flex-col gap-2">
                <span className="text-[10px] font-mono text-[var(--color-muted)] uppercase">Target Speed ({settings.speed}x)</span>
                <input 
                  type="range" min="0.5" max="3" step="0.1" 
                  value={settings.speed} 
                  onChange={(e) => setSettings({...settings, speed: parseFloat(e.target.value)})}
                  className="accent-[var(--color-heat)] w-full"
                />
              </div>
            )}

            <div className="flex flex-col gap-4 col-span-full border-t border-[var(--color-border)] pt-4 mt-2">
              <div className="flex items-center justify-between">
                <span className="text-[10px] font-mono text-[var(--color-muted)] uppercase font-bold tracking-widest">Crosshair Settings</span>
                <button
                  onClick={() => setSettings({ ...settings, crosshair: { ...settings.crosshair, enabled: !settings.crosshair.enabled } })}
                  className={`px-4 py-1 rounded-full text-[10px] font-bold uppercase border transition-all ${
                    settings.crosshair.enabled ? 'bg-[var(--color-heat)] text-white border-[var(--color-heat)]' : 'border-[var(--color-border)] text-[var(--color-muted)]'
                  }`}
                >
                  {settings.crosshair.enabled ? 'Enabled' : 'Disabled'}
                </button>
              </div>

              {settings.crosshair.enabled && (
                <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-5 gap-6 animate-in fade-in slide-in-from-top-1">
                  <div className="flex flex-col gap-2">
                    <span className="text-[9px] font-mono text-[var(--color-muted)] uppercase">Color</span>
                    <div className="flex gap-2 flex-wrap">
                      {['#00ff00', '#ff0000', '#00ffff', '#ffffff', '#ffff00', '#ff00ff'].map(c => (
                        <button
                          key={c}
                          onClick={() => setSettings({ ...settings, crosshair: { ...settings.crosshair, color: c } })}
                          className={`w-5 h-5 rounded-sm border ${settings.crosshair.color === c ? 'border-white scale-110' : 'border-black/20'}`}
                          style={{ backgroundColor: c }}
                        />
                      ))}
                    </div>
                  </div>

                  <div className="flex flex-col gap-2">
                    <span className="text-[9px] font-mono text-[var(--color-muted)] uppercase">Length ({settings.crosshair.length})</span>
                    <input 
                      type="range" min="1" max="20" step="1" 
                      value={settings.crosshair.length} 
                      onChange={(e) => setSettings({...settings, crosshair: { ...settings.crosshair, length: parseInt(e.target.value) }})}
                      className="accent-[var(--color-heat)]"
                    />
                  </div>

                  <div className="flex flex-col gap-2">
                    <span className="text-[9px] font-mono text-[var(--color-muted)] uppercase">Thickness ({settings.crosshair.thickness})</span>
                    <input 
                      type="range" min="1" max="10" step="1" 
                      value={settings.crosshair.thickness} 
                      onChange={(e) => setSettings({...settings, crosshair: { ...settings.crosshair, thickness: parseInt(e.target.value) }})}
                      className="accent-[var(--color-heat)]"
                    />
                  </div>

                  <div className="flex flex-col gap-2">
                    <span className="text-[9px] font-mono text-[var(--color-muted)] uppercase">Gap ({settings.crosshair.gap})</span>
                    <input 
                      type="range" min="0" max="20" step="1" 
                      value={settings.crosshair.gap} 
                      onChange={(e) => setSettings({...settings, crosshair: { ...settings.crosshair, gap: parseInt(e.target.value) }})}
                      className="accent-[var(--color-heat)]"
                    />
                  </div>

                  <div className="flex flex-col gap-2">
                    <span className="text-[9px] font-mono text-[var(--color-muted)] uppercase">Center Dot</span>
                    <button
                      onClick={() => setSettings({ ...settings, crosshair: { ...settings.crosshair, dot: !settings.crosshair.dot } })}
                      className={`py-1 rounded border text-[9px] font-bold uppercase transition-all ${
                        settings.crosshair.dot ? 'bg-white text-black border-white' : 'border-[var(--color-border)] text-[var(--color-muted)]'
                      }`}
                    >
                      {settings.crosshair.dot ? 'ON' : 'OFF'}
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {/* Game Canvas Wrapper */}
      <div 
        ref={containerRef}
        className={`relative w-full aspect-video min-h-[320px] bg-[var(--color-bg)] border border-[var(--color-border)] rounded-2xl overflow-hidden group transition-all duration-300 ${
          settings.crosshair.enabled ? 'cursor-none' : 'cursor-default'
        } ${isPaused ? 'grayscale-[0.5] opacity-80' : ''}`}
        onClick={(e) => {
          if (gameState === 'idle') startGame();
          else handleCanvasClick(e);
        }}
        onMouseMove={handleMouseMove}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
        role="application"
        aria-label="Target trainer game canvas"
      >
        {/* Custom Crosshair */}
        <div 
          ref={crosshairRef}
          className="pointer-events-none absolute top-0 left-0 z-50 flex items-center justify-center w-0 h-0 will-change-transform"
          style={{ 
            display: settings.crosshair.enabled ? 'flex' : 'none'
          }}
        >
          {/* Top */}
          <div 
            className="absolute"
            style={{ 
              backgroundColor: settings.crosshair.color,
              width: settings.crosshair.thickness,
              height: settings.crosshair.length,
              bottom: settings.crosshair.gap,
              left: -settings.crosshair.thickness / 2
            }}
          />
          {/* Bottom */}
          <div 
            className="absolute"
            style={{ 
              backgroundColor: settings.crosshair.color,
              width: settings.crosshair.thickness,
              height: settings.crosshair.length,
              top: settings.crosshair.gap,
              left: -settings.crosshair.thickness / 2
            }}
          />
          {/* Left */}
          <div 
            className="absolute"
            style={{ 
              backgroundColor: settings.crosshair.color,
              width: settings.crosshair.length,
              height: settings.crosshair.thickness,
              right: settings.crosshair.gap,
              top: -settings.crosshair.thickness / 2
            }}
          />
          {/* Right */}
          <div 
            className="absolute"
            style={{ 
              backgroundColor: settings.crosshair.color,
              width: settings.crosshair.length,
              height: settings.crosshair.thickness,
              left: settings.crosshair.gap,
              top: -settings.crosshair.thickness / 2
            }}
          />
          {/* Center Dot */}
          {settings.crosshair.dot && (
            <div 
              className="absolute rounded-full"
              style={{ 
                backgroundColor: settings.crosshair.color,
                width: settings.crosshair.thickness,
                height: settings.crosshair.thickness,
                left: -settings.crosshair.thickness / 2,
                top: -settings.crosshair.thickness / 2
              }}
            />
          )}
        </div>

        {/* HUD */}
        <div className={`absolute top-4 left-6 right-6 flex justify-between items-start pointer-events-none z-10 font-mono transition-opacity ${isPaused ? 'opacity-20' : 'opacity-100'}`}>
          <div className="flex gap-8">
            <div className="flex flex-col">
              <span className="text-[9px] text-[var(--color-muted)] font-bold uppercase tracking-widest">Score</span>
              <span ref={scoreHudRef} className="text-xl font-bold text-[var(--color-text)]">0</span>
            </div>
            <div className="flex flex-col">
              <span className="text-[9px] text-[var(--color-muted)] font-bold uppercase tracking-widest">FPS</span>
              <span ref={fpsHudRef} className="text-xl font-bold text-[var(--color-neon)]">0</span>
            </div>
            {mode !== 'tracking' && (
              <div className="flex flex-col">
                <span className="text-[9px] text-[var(--color-muted)] font-bold uppercase tracking-widest">Streak</span>
                <span ref={streakHudRef} className="text-xl font-bold text-white transition-all">0</span>
              </div>
            )}
          </div>
          
          <div className="flex gap-8 items-end">
            <div className="flex flex-col items-end">
              <span className="text-[9px] text-[var(--color-muted)] font-bold uppercase tracking-widest">Accuracy</span>
              <span ref={accuracyHudRef} className="text-xl font-bold text-[var(--color-text)]">0%</span>
            </div>
            <div className="flex flex-col items-end">
              <span className="text-[9px] text-[var(--color-muted)] font-bold uppercase tracking-widest">Time</span>
              <span ref={timeHudRef} className="text-xl font-bold text-[var(--color-text)]">
                {settings.duration === 0 ? '∞' : settings.duration}
              </span>
            </div>
          </div>
        </div>

        {/* Bullseye Flash */}
        {showBullseyeFlash && !isPaused && (
          <div className="absolute inset-0 pointer-events-none flex items-center justify-center z-20">
            <span className="text-4xl font-display font-black text-[#fbbf24] animate-bounce tracking-widest drop-shadow-[0_0_15px_rgba(251,191,36,0.5)]">
              BULLSEYE!
            </span>
          </div>
        )}

        {/* Start Overlay */}
        {gameState === 'idle' && (
          <div className="absolute inset-0 bg-[var(--color-bg)]/60 backdrop-blur-sm z-30 flex flex-col items-center justify-center p-8 text-center cursor-pointer group/start">
            <h3 className="text-3xl font-display font-bold mb-1 uppercase tracking-tight group-hover/start:text-[var(--color-heat)] transition-colors">{mode}</h3>
            <p className="text-[var(--color-muted)] text-xs font-mono uppercase tracking-[0.2em] mb-8">
              {mode === 'flicker' && "Reaction & Speed"}
              {mode === 'flicking' && "Large Motions"}
              {mode === 'tracking' && "Smooth Follow"}
              {mode === 'precision' && "Small Targets"}
            </p>
            <div className="flex flex-col items-center gap-3">
              <span className="px-8 py-2 border border-[var(--color-heat)] text-[var(--color-heat)] text-[10px] font-mono font-bold uppercase tracking-widest rounded-full animate-pulse">
                Click to Start
              </span>
            </div>
          </div>
        )}

        {/* Pause Overlay */}
        {isPaused && (
          <div className="absolute inset-0 bg-[var(--color-bg)]/40 backdrop-blur-[2px] z-35 flex flex-col items-center justify-center p-8 text-center pointer-events-none">
            <span className="text-xs font-mono font-bold uppercase tracking-[0.3em] text-[var(--color-muted)] animate-pulse">
              Paused
            </span>
            <span className="text-[10px] font-mono text-[var(--color-muted)] mt-2">
              Move cursor back to resume
            </span>
          </div>
        )}

        {/* Targets */}
        {gameState === 'playing' && targetsRef.current.map(t => (
          <div
            key={t.id}
            className={`absolute rounded-full pointer-events-none animate-target-spawn transition-opacity duration-300 ${isPaused ? 'opacity-30' : 'opacity-100'}`}
            style={{
              left: t.x,
              top: t.y,
              width: t.radius * 2,
              height: t.radius * 2,
              transform: 'translate(-50%, -50%)',
            }}
          >
            {/* Precision Target */}
            {mode === 'precision' ? (
              <div className="w-full h-full rounded-full border border-white/20 bg-[var(--color-heat)]/40 flex items-center justify-center">
                <div className="w-[16px] h-[16px] bg-white rounded-full shadow-[0_0_10px_rgba(255,255,255,0.8)]" />
              </div>
            ) : (
              <div className="w-full h-full rounded-full bg-[var(--color-heat)] shadow-lg shadow-[var(--color-heat)]/30 flex items-center justify-center overflow-hidden">
                <div className="w-full h-full bg-gradient-to-br from-white/40 to-transparent" />
              </div>
            )}
          </div>
        ))}

        {/* End Overlay */}
        {gameState === 'finished' && result && (
          <div className="absolute inset-0 bg-[var(--color-bg)]/95 backdrop-blur-xl z-40 flex flex-col items-center p-6 overflow-y-auto">
            {isNewRecord && (
              <div className="w-full bg-[#fbbf24]/10 border border-[#fbbf24]/30 text-[#fbbf24] py-2 px-4 mb-4 rounded text-center text-[10px] font-mono font-bold tracking-widest uppercase">
                🏅 NEW PERSONAL BEST
              </div>
            )}
            
            <h3 className="text-xl font-display font-bold mb-4 uppercase text-[var(--color-muted)] tracking-widest">Round Over</h3>
            
            <div className="grid grid-cols-3 gap-8 mb-6">
              <div className="flex flex-col items-center">
                <span className="text-[10px] font-mono text-[var(--color-muted)] uppercase mb-1">Score</span>
                <span className="text-3xl font-bold">{Math.round(result.score)}</span>
              </div>
              <div className="flex flex-col items-center">
                <span className="text-[10px] font-mono text-[var(--color-muted)] uppercase mb-1">Time</span>
                <span className="text-3xl font-bold">{result.duration}s</span>
              </div>
              <div className="flex flex-col items-center">
                <span className="text-[10px] font-mono text-[var(--color-muted)] uppercase mb-1">Hits/Shots</span>
                <span className="text-3xl font-bold">{result.hits}/{result.shots}</span>
              </div>
            </div>

            {/* Reaction Chart */}
            {mode !== 'tracking' && (
              <div className="w-full max-w-sm mb-6">
                <span className="block text-[10px] font-mono text-[var(--color-muted)] uppercase mb-2 text-center">Reaction Distribution</span>
                <canvas ref={distributionCanvasRef} width={400} height={80} className="w-full h-20" />
              </div>
            )}

            {/* Heatmap & Deltas */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 w-full max-w-lg mb-8">
              <div className="flex flex-col items-center">
                <span className="text-[10px] font-mono text-[var(--color-muted)] uppercase mb-2">Click Map</span>
                <div className="bg-[var(--color-surface)] border border-[var(--color-border)] rounded-lg overflow-hidden">
                  <canvas ref={heatmapCanvasRef} width={200} height={120} className="w-[200px] h-[120px]" />
                </div>
                <span className="text-[9px] font-mono text-[var(--color-muted)] mt-1">● hits  ○ misses</span>
              </div>
              
              <div className="flex flex-col justify-center">
                {prevResult && prevResult !== result && (
                  <div className="flex flex-col gap-2">
                     <span className="text-[10px] font-mono text-[var(--color-muted)] uppercase mb-1 border-b border-[var(--color-border)] pb-1">Comparison</span>
                     <div className="flex justify-between text-[10px] font-mono">
                        <span className="text-[var(--color-muted)]">SCORE</span>
                        <div className="flex gap-2">
                          <span className="text-[var(--color-muted)]">{Math.round(prevResult.score)}</span>
                          <span>→</span>
                          <span>{formatDelta(prevResult.score, result.score)}</span>
                        </div>
                     </div>
                     <div className="flex justify-between text-[10px] font-mono">
                        <span className="text-[var(--color-muted)]">ACCURACY</span>
                        <div className="flex gap-2">
                          <span className="text-[var(--color-muted)]">{Math.round(prevResult.accuracy)}%</span>
                          <span>→</span>
                          <span>{formatDelta(prevResult.accuracy, result.accuracy, "%")}</span>
                        </div>
                     </div>
                     <div className="flex justify-between text-[10px] font-mono">
                        <span className="text-[var(--color-muted)]">REACTION</span>
                        <div className="flex gap-2">
                          <span className="text-[var(--color-muted)]">{Math.round(prevResult.avgReaction)}ms</span>
                          <span>→</span>
                          <span>{formatDelta(prevResult.avgReaction, result.avgReaction, "ms", true)}</span>
                        </div>
                     </div>
                  </div>
                )}
              </div>
            </div>

            {/* Previous Record */}
            {records[mode] && (
              <p className="text-[10px] font-mono text-[var(--color-muted)] mb-6">
                {isNewRecord ? 'Previous best: ' : 'Best: '}
                {Math.round(records[mode]!.score)} pts · {Math.round(records[mode]!.accuracy)}% acc · {Math.round(records[mode]!.avgReaction)}ms
              </p>
            )}

            <button 
              onClick={startGame}
              className="px-10 py-2.5 bg-[var(--color-text)] text-[var(--color-bg)] font-bold rounded-full hover:opacity-90 transition-all text-sm uppercase tracking-wider"
            >
              Play Again
            </button>
          </div>
        )}
      </div>

      {/* Post-Round Detailed Stats */}
      {result && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-2">
           <div className="bg-[var(--color-surface)] border border-[var(--color-border)] p-4 rounded-xl flex flex-col gap-2">
              <div className="flex justify-between items-center">
                 <span className="text-xs font-mono font-bold uppercase text-[var(--color-muted)]">Avg Reaction Time</span>
                 <span className="text-sm font-bold">{Math.round(result.avgReaction)}ms</span>
              </div>
              <div className="h-1.5 w-full bg-[var(--color-bg)] rounded-full overflow-hidden">
                 <div 
                   className="h-full bg-[var(--color-neon)]" 
                   style={{ width: `${Math.max(0, 100 - (result.avgReaction - 100) / 3)}%` }} 
                 />
              </div>
           </div>
           <div className="bg-[var(--color-surface)] border border-[var(--color-border)] p-4 rounded-xl flex flex-col gap-2">
              <div className="flex justify-between items-center">
                 <span className="text-xs font-mono font-bold uppercase text-[var(--color-muted)]">Accuracy</span>
                 <span className="text-sm font-bold">{Math.round(result.accuracy)}%</span>
              </div>
              <div className="h-1.5 w-full bg-[var(--color-bg)] rounded-full overflow-hidden">
                 <div 
                   className="h-full bg-[var(--color-cyber)]" 
                   style={{ width: `${result.accuracy}%` }} 
                 />
              </div>
           </div>
        </div>
      )}

      {/* Insight Quote */}
      {result && (
        <div className="mt-4 p-4 border-l-2 border-[var(--color-heat)] bg-[var(--color-surface)]/30 italic text-sm text-[var(--color-muted)] leading-relaxed">
           "{getInsight()}"
        </div>
      )}
    </div>
  );
}
